package cache

import "sync"

type Config struct {
    Addr string
}

type Client struct {
    mu *sync.Mutex
    data map[string][]byte
    cfg *Config
}

func New(cfg *Config) *Client {
    return &Client{mu: &sync.Mutex{}, data: map[string][]byte{}, cfg: cfg}
}

func (c Client) Get(key string) ([]byte, bool) {
    c.mu.Lock()
    defer c.mu.Unlock()
    v, ok := c.data[key]
    return v, ok
}

func (c Client) Set(key string, val []byte) {
    c.mu.Lock()
    defer c.mu.Unlock()
    c.data[key] = val
}

func (c *Client) IsReady() bool {
    return c != nil && c.cfg != nil && c.cfg.Addr != ""
}
