package httpx

import "net/http"

var DefaultHeaders = map[string]string{
    "X-Service": "billing",
}

func init() {
    DefaultHeaders["X-Version"] = "v1"
}

func Apply(h *http.Header, extra map[string]string) {
    if h == nil {
        return
    }
    for k, v := range DefaultHeaders {
        (*h)[k] = []string{v}
    }
    for k, v := range extra {
        (*h)[k] = []string{v}
    }
}

func CloneMap(in map[string]string) map[string]string {
    out := map[string]string{}
    for k, v := range in {
        out[k] = v
    }
    return out
}
